2	import type { CollectionEntry } from "astro:content";
3	import { getCollection, render } from "astro:content";
4	import Breadcrumb from "../../components/Breadcrumb.astro";
5	import ShareButtons from "../../components/blog/ShareButtons.astro";
6	import PostNavigation from "../../components/PostNavigation.astro";
7	import RelatedPosts from "../../components/RelatedPosts.astro";
8	import BackToTop from "../../components/ui/BackToTop.astro";
9	import Tag from "../../components/ui/Tag.astro";
10	import { SITE } from "../../config/site";
11	import Layout from "../../layouts/Layout.astro";
12	import { formatDate } from "../../utils/date";
13	import { formatReadingTime, getReadingTime } from "../../utils/reading-time";
14	import { generateBreadcrumbSchema, stringifySchema } from "../../utils/schema";
15	
16	export async function getStaticPaths() {
17		const blogPosts = await getCollection("blog");
18		// 公開日でソート（新しい順）
19		const sortedPosts = blogPosts.sort(
20			(a, b) => b.data.date.getTime() - a.data.date.getTime(),
21		);
22	
23		return sortedPosts.map((post, index) => {
24			// 前後の記事（時系列順: prev=古い、next=新しい）
25			const prevPost = sortedPosts[index + 1];
26			const nextPost = sortedPosts[index - 1];
27	
28			// 関連記事（同じタグを持つ記事、最大3件）
29			const currentTags = post.data.tags || [];
30			const relatedPosts = sortedPosts
31				.filter((p) => p.id !== post.id)
32				.filter((p) => p.data.tags?.some((t: string) => currentTags.includes(t)))
33				.slice(0, 3);
34	
35			return {
36				params: { id: post.id },
37				props: {
38					post,
39					prevPost: prevPost
40						? { id: prevPost.id, title: prevPost.data.title }
41						: undefined,
42					nextPost: nextPost
43						? { id: nextPost.id, title: nextPost.data.title }
44						: undefined,
45					relatedPosts,
46				},
47			};
48		});
49	}
50	
51	const { post, prevPost, nextPost, relatedPosts } = Astro.props;
52	const { Content } = await render(post);
53	const canonicalURL = new URL(Astro.url.pathname, Astro.site);
54	const readingTime = getReadingTime(post.body || "");
55	const readingTimeText = formatReadingTime(readingTime);
56	const publishedTime = post.data.date.toISOString();
57	const modifiedTime = post.data.updatedDate
58		? post.data.updatedDate.toISOString()
59		: publishedTime;
60	const ogImageURL = new URL(`/og/blog/${post.id}.png`, Astro.site);
61	const blogSchema = {
62		"@context": "https://schema.org",
63		"@type": "BlogPosting",
64		headline: post.data.title,
65		description: post.data.excerpt,
66		datePublished: publishedTime,
67		dateModified: modifiedTime,
68		author: {
69			"@type": "Person",
70			name: SITE.author,
71			url: Astro.site?.href,
72		},
73		image: ogImageURL.href,
74		mainEntityOfPage: canonicalURL.href,
75		inLanguage: SITE.lang,
76	};
77	const breadcrumbItems = [
78		{ label: "ホーム", href: "/" },
79		{ label: "ブログ", href: "/blog" },
80		{ label: post.data.title },
81	];
82	const siteUrl = Astro.site?.href || SITE.url;
83	---
84	
85	<Layout
86	  title={`${post.data.title} | Blog | ${SITE.name}`}
87	  description={post.data.excerpt}
88	  ogType="article"
89	  ogImage={ogImageURL.href}
90	  ogImageAlt={post.data.title}
91	>
92	  <Fragment slot="head">
93	    <meta property="article:author" content={SITE.author} />
94	    <meta property="article:published_time" content={publishedTime} />
95	    {
96	      post.data.updatedDate && (
97	        <meta property="article:modified_time" content={modifiedTime} />
98	      )
99	    }
100	    <script
101	      type="application/ld+json"
102	      set:html={stringifySchema(blogSchema)}
103	    />
104	    <script
105	      type="application/ld+json"
106	      set:html={stringifySchema(generateBreadcrumbSchema(breadcrumbItems, siteUrl))}
107	    />
108	  </Fragment>
109	  <main class="mx-auto max-w-3xl px-6 py-12">
110	    <Breadcrumb items={breadcrumbItems} />
111	
112	    <a
113	      href="/blog"
114	      class="mb-6 inline-block text-sm tracking-wide text-neutral-500 hover:text-neutral-900"
115	    >
116	      ← Blog 一覧へ戻る
117	    </a>
118	
119	    <header class="mb-12 border-b border-neutral-200 pb-10">
120	      <div class="mb-4 flex flex-wrap items-center gap-3 text-sm text-neutral-500">
121	        <time class="font-medium">
122	          {formatDate(post.data.date)}
123	        </time>
124	        {
125	          post.data.updatedDate && (
126	            <span class="text-neutral-400">|</span>
127	            <span>更新: {formatDate(post.data.updatedDate)}</span>
128	          )
129	        }
130	        <span class="text-neutral-400">|</span>
131	        <span>{readingTimeText}</span>
132	      </div>
133	
134	      <h1 class="font-display mb-6 text-3xl font-bold leading-tight tracking-tight text-neutral-900 sm:text-4xl">
135	        {post.data.title}
136	      </h1>
137	
138	      {
139	        post.data.tags && post.data.tags.length > 0 && (
140	          <div class="flex flex-wrap gap-2">
141	            {post.data.tags.map((tag: string) => (
142	              <Tag>{tag}</Tag>
143	            ))}
144	          </div>
145	        )
146	      }
147	    </header>
148	
149	    <article class="prose prose-lg">
150	      <Content />
151	    </article>
152	
153	    <div class="mt-16 border-t border-neutral-200 pt-8">
154	      <ShareButtons url={canonicalURL.href} title={post.data.title} />
155	    </div>
156	
157	    <PostNavigation prevPost={prevPost} nextPost={nextPost} />
158	
159	    <RelatedPosts posts={relatedPosts} />
160	  </main>
161	  <BackToTop />
162	</Layout>
163	
164	<script>
165	  // Add copy buttons to all code blocks
166	  const copyIcon = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor"><path d="M7 3.5A1.5 1.5 0 0 1 8.5 2h3.879a1.5 1.5 0 0 1 1.06.44l3.122 3.12A1.5 1.5 0 0 1 17 6.622V12.5a1.5 1.5 0 0 1-1.5 1.5h-1v-3.379a3 3 0 0 0-.879-2.121L10.5 5.379A3 3 0 0 0 8.379 4.5H7v-1Z" /><path d="M4.5 6A1.5 1.5 0 0 0 3 7.5v9A1.5 1.5 0 0 0 4.5 18h7a1.5 1.5 0 0 0 1.5-1.5v-5.879a1.5 1.5 0 0 0-.44-1.06L9.44 6.439A1.5 1.5 0 0 0 8.378 6H4.5Z" /></svg>`;
167	  const copiedIcon = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.704 4.153a.75.75 0 0 1 .143 1.052l-8 10.5a.75.75 0 0 1-1.127.075l-4.5-4.5a.75.75 0 0 1 1.06-1.06l3.894 3.893 7.48-9.817a.75.75 0 0 1 1.05-.143Z" clip-rule="evenodd" /></svg>`;
168	
169	  document.querySelectorAll(".prose pre").forEach((pre) => {
170	    const button = document.createElement("button");
171	    button.className = "copy-button";
172	    button.innerHTML = copyIcon;
173	    button.addEventListener("click", async () => {
174	      const code = pre.querySelector("code");
175	      if (code) {
176	        await navigator.clipboard.writeText(code.textContent || "");
177	        button.classList.add("copied");
178	        button.innerHTML = copiedIcon;
179	        setTimeout(() => {
180	          button.classList.remove("copied");
181	          button.innerHTML = copyIcon;
182	        }, 2000);
183	      }
184	    });
185	    pre.appendChild(button);
186	  });
187	</script>
