---
import { Image } from "astro:assets";
import { getCollection, render } from "astro:content";
import Breadcrumb from "../../components/Breadcrumb.astro";
import { SITE } from "../../config/site";
import Layout from "../../layouts/Layout.astro";
import { generateBreadcrumbSchema, stringifySchema } from "../../utils/schema";

export async function getStaticPaths() {
	const works = await getCollection("works");
	return works.map((work) => ({
		params: { id: work.id },
		props: { work },
	}));
}

const { work } = Astro.props;
const { Content } = await render(work);
const canonicalURL = new URL(Astro.url.pathname, Astro.site);
const ogImageURL = new URL(work.data.coverImage.src, Astro.site);
const workSchema = {
	"@context": "https://schema.org",
	"@type": "CreativeWork",
	name: work.data.title,
	description: work.data.excerpt,
	image: ogImageURL.href,
	keywords: work.data.tags.join(", "),
	author: {
		"@type": "Person",
		name: SITE.author,
		url: Astro.site?.href,
	},
	url: canonicalURL.href,
	inLanguage: SITE.lang,
};
const breadcrumbItems = [
	{ label: "ホーム", href: "/" },
	{ label: "Works", href: "/works" },
	{ label: work.data.title },
];
const siteUrl = Astro.site?.href || SITE.url;
---

<Layout
  title={`${work.data.title} | Works | ${SITE.name}`}
  description={work.data.excerpt}
  ogType="article"
  ogImage={ogImageURL.href}
  ogImageAlt={work.data.title}
>
  <Fragment slot="head">
    <meta property="article:author" content={SITE.author} />
    <script
      type="application/ld+json"
      set:html={stringifySchema(workSchema)}
    />
    <script
      type="application/ld+json"
      set:html={stringifySchema(generateBreadcrumbSchema(breadcrumbItems, siteUrl))}
    />
  </Fragment>
  <main class="mx-auto max-w-4xl px-6 py-12">
    <Breadcrumb items={breadcrumbItems} />
    <div class="mb-8">
      <a
        href="/works"
        class="mb-4 inline-block text-sm text-neutral-600 hover:text-neutral-900"
      >
        ← Works一覧へ戻る
      </a>
      <h1 class="mb-4 text-4xl font-bold">{work.data.title}</h1>
      <div class="mb-6 flex flex-wrap gap-2">
        {
          work.data.tags.map((tag) => (
            <span class="rounded-full bg-neutral-100 px-4 py-2 text-sm">
              {tag}
            </span>
          ))
        }
      </div>
    </div>

    <div class="mb-8 aspect-video overflow-hidden rounded-lg">
      <Image
        src={work.data.coverImage}
        alt={work.data.title}
        class="h-full w-full object-cover"
      />
    </div>

    <article class="prose prose-lg max-w-none">
      <Content />
    </article>
  </main>
</Layout>

<script>
  const copyIcon = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor"><path d="M7 3.5A1.5 1.5 0 0 1 8.5 2h3.879a1.5 1.5 0 0 1 1.06.44l3.122 3.12A1.5 1.5 0 0 1 17 6.622V12.5a1.5 1.5 0 0 1-1.5 1.5h-1v-3.379a3 3 0 0 0-.879-2.121L10.5 5.379A3 3 0 0 0 8.379 4.5H7v-1Z" /><path d="M4.5 6A1.5 1.5 0 0 0 3 7.5v9A1.5 1.5 0 0 0 4.5 18h7a1.5 1.5 0 0 0 1.5-1.5v-5.879a1.5 1.5 0 0 0-.44-1.06L9.44 6.439A1.5 1.5 0 0 0 8.378 6H4.5Z" /></svg>`;
  const copiedIcon = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.704 4.153a.75.75 0 0 1 .143 1.052l-8 10.5a.75.75 0 0 1-1.127.075l-4.5-4.5a.75.75 0 0 1 1.06-1.06l3.894 3.893 7.48-9.817a.75.75 0 0 1 1.05-.143Z" clip-rule="evenodd" /></svg>`;

  document.querySelectorAll(".prose pre").forEach((pre) => {
    const button = document.createElement("button");
    button.className = "copy-button";
    button.innerHTML = copyIcon;
    button.addEventListener("click", async () => {
      const code = pre.querySelector("code");
      if (code) {
        await navigator.clipboard.writeText(code.textContent || "");
        button.classList.add("copied");
        button.innerHTML = copiedIcon;
        setTimeout(() => {
          button.classList.remove("copied");
          button.innerHTML = copyIcon;
        }, 2000);
      }
    });
    pre.appendChild(button);
  });
</script>

