1	---
2	// フィルタリング・ソートコンポーネント
3	// クライアントサイドでリストのフィルタ・ソートを行う
4	
5	interface Props {
6		tags: string[];
7		sortOptions?: { value: string; label: string }[];
8		containerId: string;
9	}
10	
11	const {
