56	        </label>
57	        <select
58	          id={`sort-${containerId}`}
59	          class="sort-select rounded-lg border border-neutral-300 bg-white px-3 py-1.5 text-sm transition-colors focus:border-[var(--primary-color)] focus:outline-none focus:ring-2 focus:ring-[var(--primary-color)] focus:ring-offset-1"
60	        >
61	          {sortOptions.map((option) => (
62	            <option value={option.value}>{option.label}</option>
63	          ))}
