75	      class="reset-filter-btn ml-2 text-sm text-neutral-500 underline transition-colors hover:text-neutral-700"
76	    >
77	      リセット
78	    </button>
79	  </div>
80	
81	  <!-- 結果数表示 -->
82	  <div class="flex items-center justify-between text-sm text-neutral-500">
83	    <span class="result-count"></span>
84	  </div>
85	
86	  <!-- 空の検索結果状態 -->
87	  <div class="empty-state hidden py-12 text-center" role="status" aria-live="polite">
88	    <div class="mb-4 text-neutral-400">
89	      <svg
90	        class="mx-auto h-12 w-12"
91	        fill="none"
92	        stroke="currentColor"
93	        viewBox="0 0 24 24"
94	        aria-hidden="true"
95	      >
96	        <path
97	          stroke-linecap="round"
98	          stroke-linejoin="round"
99	          stroke-width="1.5"
100	          d="M9.172 16.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"
101	        ></path>
102	      </svg>
103	    </div>
104	    <h3 class="mb-2 text-lg font-medium text-neutral-900">
105	      該当する項目がありません
106	    </h3>
107	    <p class="mb-4 text-sm text-neutral-500">
108	      条件を変更して再度お試しください
109	    </p>
110	    <button
111	      type="button"
112	      class="reset-all-btn rounded-full border border-[var(--primary-color)] px-4 py-2 text-sm font-medium text-[var(--primary-color)] transition-colors hover:bg-[var(--primary-color)] hover:text-white"
113	    >
114	      フィルターをリセット
115	    </button>
116	  </div>
117	</div>
118	
119	<style>
120	  .filter-chip {
121	    display: inline-flex;
122	    align-items: center;
123	    gap: 0.25rem;
124	    border-radius: 9999px;
125	    border: 1px solid var(--border-color);
126	    padding: 0.25rem 0.75rem;
127	    font-size: 0.875rem;
128	    font-weight: 500;
129	    transition: all 0.2s ease;
130	    background-color: var(--bg-primary);
131	    color: var(--text-secondary);
132	  }
133	
134	  .filter-chip:hover {
135	    border-color: var(--primary-color);
136	    color: var(--primary-color);
137	  }
138	
139	  .filter-chip:focus-visible {
140	    outline: 2px solid var(--primary-color);
141	    outline-offset: 2px;
142	  }
143	
144	  .filter-chip.active {
145	    border-color: var(--primary-color);
146	    background-color: var(--primary-color);
147	    color: white;
148	  }
149	
150	  /* Smooth filter transition */
151	  [data-item] {
152	    transition: opacity 0.2s ease, transform 0.2s ease;
153	  }
154	
155	  [data-item].filter-hidden {
156	    opacity: 0;
157	    transform: scale(0.95);
158	    pointer-events: none;
159	    position: absolute;
160	    visibility: hidden;
161	  }
162	
163	  @media (prefers-reduced-motion: reduce) {
164	    .filter-chip,
165	    [data-item] {
166	      transition: none;
167	    }
168	  }
169	</style>
170	
171	<script is:inline>
172	  (function() {
173	    document.querySelectorAll("[data-filter-sort]").forEach(function(filterComponent) {
174	      const containerId = filterComponent.dataset.container;
175	      const container = document.getElementById(containerId);
176	      if (!container) return;
177	
