366	
367	```ts
368	// Client-side auth utilities for localStorage-based authentication
369	
370	export interface User {
371	  username: string;
372	  burritoConsiderations: number;
373	}
374	
375	export function getCurrentUser(): User | null {
376	  if (typeof window === "undefined") return null;
377	
378	  const username = localStorage.getItem("currentUser");
379	  if (!username) return null;
380	
381	  const considerations = parseInt(
382	    localStorage.getItem("burritoConsiderations") || "0",
383	    10,
384	  );
385	
386	  return {
387	    username,
388	    burritoConsiderations: considerations,
389	  };
390	}
391	
392	export function login(username: string, password: string): boolean {
393	  if (!username || !password) return false;
394	
395	  localStorage.setItem("currentUser", username);
396	  // Initialize burrito considerations if not set
397	  if (!localStorage.getItem("burritoConsiderations")) {
398	    localStorage.setItem("burritoConsiderations", "0");
399	  }
400	
401	  return true;
402	}
403	
404	export function logout(): void {
405	  localStorage.removeItem("currentUser");
406	  localStorage.removeItem("burritoConsiderations");
407	}
408	
409	export function incrementBurritoConsiderations(): number {
410	  const current = parseInt(
411	    localStorage.getItem("burritoConsiderations") || "0",
412	    10,
413	  );
414	  const newCount = current + 1;
415	  localStorage.setItem("burritoConsiderations", newCount.toString());
416	  return newCount;
417	}
418	
