---
import "../styles/global.css";
import Footer from "../components/Footer.astro";
import Header from "../components/Header.astro";
import { SITE } from "../config/site";
import { generateWebSiteSchema, stringifySchema } from "../utils/schema";

interface Props {
	title?: string;
	description?: string;
	ogImage?: string;
	ogImageAlt?: string;
	ogSiteName?: string;
	ogType?: "website" | "article" | "book";
	noHeader?: boolean;
	noFooter?: boolean;
}

const {
	title = SITE.name,
	description = SITE.description,
	ogImage = "/og-image.png",
	ogImageAlt = title,
	ogSiteName = SITE.name,
	ogType = "website",
	noHeader = false,
	noFooter = false,
} = Astro.props;

const canonicalURL = new URL(Astro.url.pathname, Astro.site);
const ogImageURL = new URL(ogImage, Astro.site);
---

<!doctype html>
<html lang="ja">
	<head>
		<meta charset="UTF-8" />
		<meta name="viewport" content="width=device-width" />
		<link rel="icon" type="image/svg+xml" href="/favicon.svg" />
		<meta name="generator" content={Astro.generator} />
		<meta name="color-scheme" content="light" />

		<!-- Primary Meta Tags -->
		<title>{title}</title>
		<meta name="title" content={title} />
		<meta name="description" content={description} />
		<meta name="author" content={SITE.author} />
		<link rel="canonical" href={canonicalURL} />

		<!-- Open Graph / Facebook -->
		<meta property="og:type" content={ogType} />
		<meta property="og:url" content={canonicalURL} />
		<meta property="og:title" content={title} />
		<meta property="og:description" content={description} />
		<meta property="og:image" content={ogImageURL} />
		<meta property="og:image:alt" content={ogImageAlt} />
		<meta property="og:site_name" content={ogSiteName} />
		<meta property="og:locale" content={SITE.locale} />

		<!-- Twitter -->
		<meta name="twitter:card" content="summary_large_image" />
		<meta name="twitter:url" content={canonicalURL} />
		<meta name="twitter:title" content={title} />
		<meta name="twitter:description" content={description} />
		<meta name="twitter:image" content={ogImageURL} />
		<meta name="twitter:image:alt" content={ogImageAlt} />

		<!-- 構造化データ (JSON-LD) -->
		<script
			type="application/ld+json"
			set:html={stringifySchema(generateWebSiteSchema(Astro.site?.href || SITE.url))}
		></script>
		<slot name="head" />
		<noscript>
			<style>
				[data-animate] {
					opacity: 1 !important;
					transform: none !important;
				}
			</style>
		</noscript>
	</head>
	<body class="bg-white text-neutral-900 transition-colors">
		<!-- スキップリンク -->
		<a href="#main-content" class="skip-link">
			コンテンツにスキップ
		</a>
		{!noHeader && <Header />}
		<div id="main-content">
			<slot />
		</div>
		{!noFooter && <Footer />}
		<script>
			import "../scripts/animations/observer.ts";
		</script>
		<script is:inline>
			(() => {
				const modelContext = navigator.modelContext;
				if (!modelContext) return;

				const siteOverviewTool = {
					name: "get_site_overview",
					description:
						"Return a concise overview of ta93abe.com, including public sections and machine-readable discovery URLs.",
					inputSchema: {
						type: "object",
						properties: {},
						additionalProperties: false,
					},
					execute: async () => ({
						site: "https://ta93abe.com/",
						sections: [
							"https://ta93abe.com/works/",
							"https://ta93abe.com/blog/",
							"https://ta93abe.com/slides/",
							"https://ta93abe.com/bookshelf/",
							"https://ta93abe.com/tools/",
							"https://ta93abe.com/links/",
						],
						discovery: {
							llms: "https://ta93abe.com/llms.txt",
							apiCatalog: "https://ta93abe.com/.well-known/api-catalog",
							mcpServerCard:
								"https://ta93abe.com/.well-known/mcp/server-card.json",
							agentSkills:
								"https://ta93abe.com/.well-known/agent-skills/index.json",
							auth: "https://ta93abe.com/auth.md",
						},
					}),
					annotations: {
						readOnlyHint: true,
					},
				};

				if (typeof modelContext.registerTool === "function") {
					modelContext.registerTool(siteOverviewTool);
				} else if (typeof modelContext.provideContext === "function") {
					modelContext.provideContext({ tools: [siteOverviewTool] });
				}
			})();
		</script>
	</body>
</html>

<style>
	html,
		body {
			margin: 0;
			width: 100%;
			height: 100%;
			font-family: "Shippori Mincho", "Noto Serif JP", serif;
		}

	/* スキップリンク */
	.skip-link {
		position: absolute;
		top: -100%;
		left: 50%;
		transform: translateX(-50%);
		padding: 0.75rem 1.5rem;
		background: var(--primary-color);
		color: white;
		font-weight: 600;
		border-radius: 0 0 0.5rem 0.5rem;
		text-decoration: none;
		z-index: 50;
		transition: top 0.2s ease-out;
	}

	.skip-link:focus-visible {
		top: 0;
	}

	@media (prefers-reduced-motion: reduce) {
		.skip-link {
			transition: none;
		}
	}

</style>

