interface Props {
	url: string;
	title: string;
	class?: string;
}

const { url, title, class: className = "" } = Astro.props;

const encodedUrl = encodeURIComponent(url);
const encodedTitle = encodeURIComponent(title);

const shareLinks = [
	{
