<div class:list={["flex flex-wrap items-center gap-3", className]}>
	<span class="text-sm text-neutral-600">シェア:</span>
	{shareLinks.map((link) => (
		<a
			href={link.href}
			target="_blank"
			rel="noopener noreferrer"
			class="inline-flex items-center gap-1.5 rounded-full bg-neutral-100 px-3 py-1.5 text-sm text-neutral-700 transition-colors hover:bg-neutral-200 share-link"
			title={link.label}
			data-platform={link.name}
			data-url={url}
			data-title={title}
		>
			<span set:html={link.icon} />
			<span class="hidden sm:inline">{link.name}</span>
		</a>
	))}
	<button
		id="copy-url-btn"
		class="inline-flex items-center gap-1.5 rounded-full bg-neutral-100 px-3 py-1.5 text-sm text-neutral-700 transition-colors hover:bg-neutral-200"
		title="URLをコピー"
		data-url={url}
	>
		<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" class="size-5">
			<path d="M12.232 4.232a2.5 2.5 0 0 1 3.536 3.536l-1.225 1.224a.75.75 0 0 0 1.061 1.06l1.224-1.224a4 4 0 0 0-5.656-5.656l-3 3a4 4 0 0 0 .225 5.865.75.75 0 0 0 .977-1.138 2.5 2.5 0 0 1-.142-3.667l3-3Z" />
			<path d="M11.603 7.963a.75.75 0 0 0-.977 1.138 2.5 2.5 0 0 1 .142 3.667l-3 3a2.5 2.5 0 0 1-3.536-3.536l1.225-1.224a.75.75 0 0 0-1.061-1.06l-1.224 1.224a4 4 0 1 0 5.656 5.656l3-3a4 4 0 0 0-.225-5.865Z" />
		</svg>
		<span id="copy-text" class="hidden sm:inline">コピー</span>
	</button>
</div>

<script>
	const copyBtn = document.getElementById("copy-url-btn");
	const copyText = document.getElementById("copy-text");

	if (copyBtn && copyText) {
		copyBtn.addEventListener("click", async () => {
			const url = copyBtn.dataset.url;
			if (url) {
				await navigator.clipboard.writeText(url);
				copyText.textContent = "コピー済み";
				setTimeout(() => {
					copyText.textContent = "コピー";
				}, 2000);
			}
		});
	}
</script>

