<style>
  .hero-section {
    position: relative;
    min-height: 100dvh;
    display: flex;
    align-items: center;
    justify-content: center;
    overflow: hidden;
    background: var(--bg-primary);
  }

  .hero-content {
    position: relative;
    z-index: 10;
    text-align: center;
    padding: 2rem;
  }

  .hero-greeting {
    margin-bottom: 1rem;
  }

  .hero-greeting span {
    display: inline-block;
    font-size: 0.875rem;
    text-transform: uppercase;
    color: var(--text-muted);
  }

  .hero-title {
    font-size: clamp(3rem, 10vw, 7rem);
    font-weight: 700;
    line-height: 1;
    margin: 0;
    color: var(--text-primary);
  }

  .hero-name {
    display: inline-block;
    color: var(--text-primary);
  }

  .hero-description {
    font-size: clamp(1.125rem, 2.5vw, 1.5rem);
    color: var(--text-secondary);
    margin: 1.5rem 0 2.5rem;
    font-weight: 400;
  }

  .hero-cta {
    display: flex;
    gap: 1rem;
    justify-content: center;
    flex-wrap: wrap;
  }

  @media (max-width: 768px) {
    .hero-section {
      min-height: 100svh;
    }
  }
</style>

<script is:inline>
  document.querySelectorAll(".hero-cta [data-cta]").forEach(function(btn) {
    btn.addEventListener("click", function() {
      window.posthog?.capture("hero_cta_clicked", {
        cta_label: btn.dataset.cta,
        cta_href: btn.getAttribute("href"),
      });
    });
  });
</script>

